import * as fs from "node:fs";
import * as path from "node:path";
import type { LspExtensionConfig, LSPServerConfig } from "./types.ts";

const DEFAULT_CONFIG: LspExtensionConfig = {
	enabled: true,
	autoStart: true,
	idleTimeoutMs: 300_000,
	syncContent: true,
	autoDiagnostics: true,
	servers: {},
	customServers: [],
};

export function loadConfig(cwd: string): { config: LspExtensionConfig; path: string } {
	const configPath = path.join(cwd, ".pi", "pi-lsp.json");
	if (!fs.existsSync(configPath)) {
		return { config: { ...DEFAULT_CONFIG }, path: configPath };
	}
	try {
		const raw = fs.readFileSync(configPath, "utf-8");
		const parsed = JSON.parse(raw) as Partial<LspExtensionConfig>;
		return {
			config: {
				enabled: parsed.enabled ?? DEFAULT_CONFIG.enabled,
				autoStart: parsed.autoStart ?? DEFAULT_CONFIG.autoStart,
				idleTimeoutMs: parsed.idleTimeoutMs ?? DEFAULT_CONFIG.idleTimeoutMs,
				syncContent: parsed.syncContent ?? DEFAULT_CONFIG.syncContent,
				autoDiagnostics: parsed.autoDiagnostics ?? DEFAULT_CONFIG.autoDiagnostics,
				servers: { ...DEFAULT_CONFIG.servers, ...(parsed.servers ?? {}) },
				customServers: validateCustomServers(parsed.customServers),
			},
			path: configPath,
		};
	} catch {
		return { config: { ...DEFAULT_CONFIG }, path: configPath };
	}
}

function validateCustomServers(servers: unknown): LSPServerConfig[] {
	if (!Array.isArray(servers)) return [];
	const valid: LSPServerConfig[] = [];
	for (const server of servers) {
		if (
			typeof server === "object" && server !== null &&
			typeof (server as Record<string, unknown>).language === "string" &&
			Array.isArray((server as Record<string, unknown>).command) &&
			Array.isArray((server as Record<string, unknown>).extensions)
		) {
			valid.push(server as LSPServerConfig);
		}
	}
	return valid;
}

// ─── LSP Protocol Types ───────────────────────────────────────────────────────

export interface Position {
	line: number;
	character: number;
}

export interface Range {
	start: Position;
	end: Position;
}

export interface Location {
	uri: string;
	range: Range;
}

export interface Diagnostic {
	range: Range;
	severity?: DiagnosticSeverity;
	code?: string | number;
	source?: string;
	message: string;
	relatedInformation?: DiagnosticRelatedInformation[];
}

export const enum DiagnosticSeverity {
	Error = 1,
	Warning = 2,
	Information = 3,
	Hint = 4,
}

export interface DiagnosticRelatedInformation {
	location: Location;
	message: string;
}

export interface SymbolInformation {
	name: string;
	kind: SymbolKind;
	location: Location;
	containerName?: string;
}

export interface DocumentSymbol {
	name: string;
	kind: SymbolKind;
	range: Range;
	selectionRange: Range;
	children?: DocumentSymbol[];
}

export const enum SymbolKind {
	File = 1,
	Module = 2,
	Namespace = 3,
	Package = 4,
	Class = 5,
	Method = 6,
	Property = 7,
	Field = 8,
	Constructor = 9,
	Enum = 10,
	Interface = 11,
	Function = 12,
	Variable = 13,
	Constant = 14,
	String = 15,
	Number = 16,
	Boolean = 17,
	Array = 18,
	Object = 19,
	Key = 20,
	Null = 21,
	EnumMember = 22,
	Struct = 23,
	Event = 24,
	Operator = 25,
	TypeParameter = 26,
}

export interface TextEdit {
	range: Range;
	newText: string;
}

export interface TextDocumentEdit {
	textDocument: { uri: string; version: number | null };
	edits: TextEdit[];
}

export interface WorkspaceEdit {
	changes?: Record<string, TextEdit[]>;
	documentChanges?: TextDocumentEdit[];
}

export interface CodeAction {
	title: string;
	kind?: string;
	diagnostics?: Diagnostic[];
	edit?: WorkspaceEdit;
	command?: { title: string; command: string; arguments?: unknown[] };
}

export interface Hover {
	contents: unknown;
	range?: Range;
}

export interface Command {
	title: string;
	command: string;
	arguments?: unknown[];
}

// ─── JSON-RPC 2.0 Types ──────────────────────────────────────────────────────

export interface JsonRpcRequest {
	jsonrpc: "2.0";
	id: number | string;
	method: string;
	params?: unknown;
}

export interface JsonRpcNotification {
	jsonrpc: "2.0";
	method: string;
	params?: unknown;
}

export interface JsonRpcResponse {
	jsonrpc: "2.0";
	id: number | string;
	result?: unknown;
	error?: JsonRpcError;
}

export interface JsonRpcError {
	code: number;
	message: string;
	data?: unknown;
}

// ─── LSP Server Configuration ────────────────────────────────────────────────

export interface LSPServerConfig {
	language: string;
	command: string[];
	extensions: string[];
	detectionFiles: string[];
	installHint?: string;
	enabled?: boolean;
}

// ─── Client State ────────────────────────────────────────────────────────────

export const enum LSPClientState {
	Stopped = "stopped",
	Initializing = "initializing",
	Ready = "ready",
	ShuttingDown = "shutting_down",
}

// ─── Document Sync ───────────────────────────────────────────────────────────

