}

// ─── Config ──────────────────────────────────────────────────────────────────

export interface LspExtensionConfig {
	enabled: boolean;
	autoStart: boolean;
	idleTimeoutMs: number;
	syncContent: boolean;
	autoDiagnostics: boolean;
	servers: Record<string, { enabled?: boolean; command?: string[] }>;
	customServers: LSPServerConfig[];
